    source_url: "https://www.sodnapraksa.si/search.php?q=&advanceSerch=1&database[SOVS]=SOVS&trib_title[Vrhovno sodišče]=\"Vrhovno sodišče\"&dep_title[Civilni oddelek]=\"Civilni oddelek\"&dep_title[Delovno-socialni oddelek]=\"Delovno-socialni oddelek\"&dep_title[Gospodarski oddelek]=\"Gospodarski oddelek\"&dep_title[Kazenski oddelek]=\"Kazenski oddelek\"&dep_title[Upravni oddelek]=\"Upravni oddelek\"&meet_dateFrom=02.03.2022&meet_dateTo=29.05.2026&order=date&direction=desc&_submit=išči&rowsPerPage=20&page=36&id=2015081111487206",
